sql:
SELECT shoe_name, retail_price
FROM shoes
WHERE updated_at = (
  SELECT MAX(updated_at) 
  FROM shoes
);

SELECT shoe_name
FROM shoes
WHERE heel_to_toe_cm = (SELECT MAX(heel_to_toe_cm) FROM shoes);

SELECT shoes.shoe_name, colors.color_name 
FROM shoes 
JOIN colors ON shoes.primary_color_id = colors.color_id;

SELECT shoe_id 
FROM shoes 
WHERE retail_price > (SELECT AVG(retail_price) FROM shoes);

SELECT COUNT(shoe_id) 
FROM shoes
WHERE material_id = (SELECT material_id FROM materials WHERE material_name = 'Leather');

SELECT shoe_name 
FROM shoes 
WHERE shoe_id = 0;

SELECT S.shoe_name
FROM shoes S
WHERE S.retail_price > (SELECT AVG(retail_price) FROM shoes);

SELECT SUM(sustainability_rating * quantity) AS total_sustainability_rating
FROM shoe_materials
WHERE shoe_id = 0 AND material_id != 2;

SELECT m.material_name, m.supplier_id, m.sustainability_rating
FROM materials m
WHERE m.material_id IN (SELECT sm.material_id FROM shoe_materials sm);
